import numpy as np

def l2_normalize(x: np.ndarray) -> np.ndarray:
    norms = np.linalg.norm(x, axis=1, keepdims=True)
    return x / (norms + 1e-8)

def clip_logits(I_emb: np.ndarray, T_emb: np.ndarray, log_temp: float) -> np.ndarray:
    # I_emb, T_emb are already normalized
    temp = np.exp(log_temp)
    return (I_emb @ T_emb.T) * temp  # (N, N)

def _cross_entropy(logits, labels):
    """Row-wise cross-entropy."""
    # Numerically stable softmax
    logits = logits - logits.max(axis=1, keepdims=True)
    log_softmax = logits - np.log(np.sum(np.exp(logits), axis=1, keepdims=True))
    return -np.mean(log_softmax[np.arange(len(labels)), labels])

def clip_loss(logits: np.ndarray) -> float:
    N = logits.shape[0]
    labels = np.arange(N)
    # Image -> Text cross-entropy
    loss_i2t = _cross_entropy(logits, labels)
    # Text -> Image cross-entropy
    loss_t2i = _cross_entropy(logits.T, labels)
    return float((loss_i2t + loss_t2i) / 2)
